from celery import chord, group

@app.task
def process_item(item):
    return item * 2

@app.task
def summarize(results):
    return sum(results)

# Chord: process items, then summarize
result = chord(
    group(process_item.s(i) for i in range(10)),
    summarize.s()
)()
